from __future__ import annotations
from pathlib import Path
from .common import ROOT,read_yaml,sha256_file,write_json
from tools.audit.validate_regression_bundle import validate

def relative_from_manifest(path,manifest): return Path(path).resolve().relative_to(ROOT.resolve()).as_posix() if False else Path(__import__('os').path.relpath(Path(path).resolve(),manifest.parent.resolve())).as_posix()

def build_manifest(item,input_lock,prediction_path,manifest_path,policy_result_path,compatibility_result,reference_post_hoc=False):
    schema=read_yaml(ROOT/"ml/experiments/v0_3_11/feature_schema.yaml")["ordered_features"]; rows=input_lock["rows"]
    source_lock=ROOT/item["validation_lock_path"]; feature=ROOT/item["feature_table_path"]; prediction=Path(prediction_path); policy=Path(policy_result_path)
    rel=lambda p: relative_from_manifest(p,manifest_path)
    data={"stage_id":"v0.3.12.2","protocol_sha256":input_lock.get("v03122_protocol_sha256") or input_lock.get("regression_protocol_sha256"),"campaign_manifest_sha256":sha256_file(source_lock),"source_commit_sha256":"0df5568ce5935dff7dff6612e85198f10d7b18d7","dependency_lock_sha256":sha256_file(ROOT/"ml/requirements.txt"),"feature_table_path":rel(feature),"feature_table_sha256":sha256_file(feature),"feature_count":51,"ordered_feature_names":schema,"feature_schema_sha256":sha256_file(ROOT/"ml/experiments/v0_3_11/feature_schema.yaml"),"row_count":len(rows),"ordered_row_ids":[r["immutable_row_id"] for r in rows],"row_mapping_sha256":input_lock.get("v038_ordered_row_mapping_sha256") or input_lock.get("ordered_row_mapping_sha256"),"row_identity_version":"v03122-causal-v1","run_mapping":{r["immutable_row_id"]:r["run_id"] for r in rows},"run_mapping_sha256":input_lock.get("v038_run_mapping_sha256") or input_lock.get("ordered_row_mapping_sha256"),"causal_order_mapping":{r["immutable_row_id"]:r["causal_order"] for r in rows},"causal_order_mapping_sha256":input_lock.get("v038_causal_order_mapping_sha256") or input_lock.get("ordered_row_mapping_sha256"),"activity_key_source_fields":["run_id","frozen_episode_mapping_key"],"activity_key_mapping_sha256":input_lock.get("v038_activity_key_mapping_sha256") or input_lock.get("activity_key_mapping_sha256"),"label_table_path":rel(source_lock),"label_table_sha256":sha256_file(source_lock),"label_schema_version":"historical-validation-lock-v1","episode_mapping_path":rel(source_lock),"episode_mapping_sha256":sha256_file(source_lock),"frozen_episode_mapping_sha256":input_lock.get("v038_episode_mapping_sha256") or input_lock.get("episode_mapping_sha256"),"episode_mapping_created_before_prediction":True,"capture_manifest_path":rel(source_lock),"capture_manifest_sha256":sha256_file(source_lock),"historical_candidate_id":"v0311:19176acb401be2d4","candidate_manifest_sha256":"ad8ff7ea42a28847dcf0fc92b76c176d3f0dda0e874bd865dfa4ea3f6fcf888c","immutable_prediction_path":rel(prediction),"immutable_prediction_sha256":sha256_file(prediction),"prediction_schema_version":"v03122-causal-reference-v1","metric_policy_sha256":sha256_file(ROOT/"ml/experiments/v0_3_12_2/metric_policy.yaml"),"policy_result_path":rel(policy),"policy_result_sha256":sha256_file(policy),"compatibility_self_test_result":compatibility_result,"regression_bundle_complete":True,"reference_manifest_created_post_hoc":reference_post_hoc}
    manifest_path.write_text(__import__('yaml').safe_dump(data,allow_unicode=True,sort_keys=False),encoding="utf-8",newline="\n"); return data

def validate_manifest(path): return validate(path,metadata_only=False)
